parameters.jsCode:
const body = $input.first().json.body || {};
const objective = (body.objective || '').trim();
const input_prompt = (body.input_prompt || '').trim();

const errors = [];
if (!objective) {
  errors.push("Le champ 'objective' est requis et ne peut pas être vide");
}
if (!input_prompt) {
  errors.push("Le champ 'input_prompt' est requis et ne peut pas être vide");
}

return [{
  json: {
    is_valid: errors.length === 0,
    errors,
    body
  }
}];

const rawText = ($input.first().json.text || '').trim();

let parsed;
try {
  const cleaned = rawText
    .replace(/^```json\s*/im, '')
    .replace(/^```\s*/im, '')
    .replace(/```\s*$/im, '')
    .trim();
  parsed = JSON.parse(cleaned);
} catch(e) {
  parsed = {
    prompt_final: '# Prompt Optimisé\n\nErreur de parsing - Réponse brute du LLM:\n\n' + rawText,
    variables: [],
    questions: ['Erreur: la réponse du LLM nétait pas du JSON valide. Vérifiez le prompt et réessayez.'],
    checklist_prereqs: [],
    acceptance_tests: []
  };
}

const result = {
  prompt_final: parsed.prompt_final || rawText,
  variables: Array.isArray(parsed.variables) ? parsed.variables : [],
  questions: Array.isArray(parsed.questions) ? parsed.questions : [],
  checklist_prereqs: Array.isArray(parsed.checklist_prereqs) ? parsed.checklist_prereqs : [],
  acceptance_tests: Array.isArray(parsed.acceptance_tests) ? parsed.acceptance_tests : [],
  meta: {
    version: 'DEV__PromptOptimizer__v1',
    timestamp: new Date().toISOString()
  }
};

return [{ json: result }];

